#!/usr/bin/env bash
# workflow-3.sh — 海外求职弧线 SOP walkthrough for 求职 / 面试辅导(求职教练视角 — 求职定位与职业叙事 / 简历与 ATS 优化 / 求职渠道与内推策略 / 职场社交 / 行为面试与专业面试 / 面试心理与表达 / 谈薪与 offer 决策 / 校招与应届生 / 转行求职 / 特殊群体求职 / 求职教练的执业经营 — 涵盖中国大陆求职生态 + 海外英语区求职体系,两套差异极大).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="求职 / 面试辅导(求职教练视角 — 求职定位与职业叙事 / 简历与 ATS 优化 / 求职渠道与内推策略 / 职场社交 / 行为面试与专业面试 / 面试心理与表达 / 谈薪与 offer 决策 / 校招与应届生 / 转行求职 / 特殊群体求职 / 求职教练的执业经营 — 涵盖中国大陆求职生态 + 海外英语区求职体系,两套差异极大)"
WORKFLOW="海外求职弧线"

usage() {
  cat <<EOF
workflow-3.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-3.sh             # interactive
  ./workflow-3.sh --dry-run
  ./workflow-3.sh --json
  ./workflow-3.sh --explain
  ./workflow-3.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "海外求职弧线" 工作流。

一句话: 求职者在海外英语区从「定位」到「谈定 offer」的全过程 —— 海外的特征是 **LinkedIn 为中枢 + recruiter screen + networking 权重高**（尤其科技 / 咨询 / 中高层级岗位），简历严格匿名化（无照片 / 年龄 / 婚育，反歧视），招聘 rolling 无统一时间窗。

入门 SOP 共 6 步, 失败模式自检 5 项。

相关心智模型:
  • 定位先于一切执行（定位错了，后面是高效地做错事）: 求职的第一性问题不是「简历怎么写 / 该投哪」，而是「要找哪一类岗位 + 为什么是我」—— 目标不收敛时，改简历、海投、练面试都是在高效地做错的事。
  • 从招聘方 / ATS / 岗位的痛点出发倒推（不是从「我想要什么」出发）: 简历、触达、面试答案的组织原点是「这个岗位 / 招聘经理在解决什么问题」，不是「我想说什么」—— 招聘经理立项前往往已缺人 6-12 个月，他要的是「缓解」。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定位与目标公司清单**（详见 W5）：收敛目标岗位 / 行业 / 地点，列一份目标公司清单（海外更强调「锁定少数目标公司深耕」而非广投）。**跳过会发生什么**：无差别海投 → 简历无法针对性、networking 没有方向、面试讲不出动机。"
  "**简历过 ATS + 匿名化**：做一份海外格式简历（匿名化：无照片 / 年龄 / 婚育；动词开头 + 量化成就），用 Jobscan / Teal 做关键词匹配度检查（详见 W6）。**跳过会发生什么**：简历被 ATS 解析失败 / 关键词不匹配 → 网申路径下连人都到不了；带照片 / 年龄反而触发反歧视流程问题。"
  "**networking / 内推**：在 LinkedIn 找目标公司在职者发起弱关系连接、做信息面谈（informational interview，铁律「第一次不要工作」）、争取内推。**跳过会发生什么**：海外科技 / 咨询 / 高层级岗位内推权重高，纯网申命中率低；hidden job market 完全进不去（evidence: [T03-S017]）。"
  "**网申 + recruiter screen**：通过公司官网 / LinkedIn 投递；通过初筛后是 recruiter screen（HR / recruiter 的初步电话面，过岗位匹配 + 期望薪资 + 时间线）。**跳过会发生什么**：没有投递入口；recruiter screen 没准备 → 期望薪资报错 / 讲不清动机，第一关就挂。"
  "**多轮面试**：行为面（STAR）+ 专业面（技术岗 coding / 系统设计、咨询 case、PM 产品题）+ 有时含 onsite / 多人轮面。**跳过会发生什么**：不按类型准备 → 行为面流水账、专业面露怯。"
  "**谈薪 + offer 决策 + 签证确认**（详见 W7）：海外谈薪空间通常比国内大，按 base + bonus + 股票总包谈；国际学生 / 移民还要确认 offer 能否支持签证（如美国 H1B / OPT、英国工签等）。**跳过会发生什么**：只比 base 不比总包 → 决策失真；不确认签证 → offer 拿到了但身份走不通。"
)
declare -a FAILURE_MODES=(
  "**无差别海投、零 networking**：触发原因 = 「投得多 = 努力」的误区；后果 = 在 networking 权重高的赛道命中率极低、hidden job market 完全进不去。怎么避免：先判断目标赛道的 networking 权重，权重高则 networking 触达优先于网申。"
  "**信息面谈一开口就要工作 / 要内推**：触发原因 = 把 informational interview 当「变相求职」；后果 = 破坏信任、对方设防、关系做死。怎么避免：守「第一次不要工作」铁律，先建立关系和了解。"
  "**简历带照片 / 年龄 / 把国内格式照搬**：触发原因 = 不懂海外匿名化反歧视惯例；后果 = 显得不专业，甚至给招聘方制造合规顾虑。怎么避免：海外简历严格匿名化，按目标地区惯例做。"
  "**把 ghosting 解读成「我一定很差」**：触发原因 = 不了解 ghosting 高度结构性（市场差 + 招聘方流程问题）；后果 = 自我否定、放弃、心态崩。怎么避免：教练做预期校准 —— ghosting 是市场常态不是个人评判，把精力放回可控部分（W 系列各环节）。"
  "**国际学生到 offer 阶段才查签证**：触发原因 = 把签证当「后面再说」；后果 = offer 拿到了但岗位 / 公司不 sponsor，前功尽弃。怎么避免：把签证可行性当定位的前置筛选条件。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-3-walkthrough"
fi
